// Problem 1: User Profile Extractor
// Given the object below, destructure name, age, and country.
// country should default to "Bangladesh" if missing.
const profile = { name: "Sabbir", age: 25, city: "Dhaka" };
// Your code here:
const {name, age, city, country = "Bangladesh"} = profile;
console.log(`${name} is ${age} years old form ${city} in ${country}`)

// Problem 2: Rename on Destructure
// Destructure the object below, but rename:
//   id → userId, email → userEmail
const account = { id: 42, email: "sabbir@dev.com", role: "admin" };
// Your code here:
const {id : userId, email: userEmail} = account;
console.log(userId, userEmail)

// Problem 3: Nested Destructuring
// Extract street and zip from the nested address object.
const person = {
  name: "Alice",
  address: {
    street: "123 Main St",
    zip: "1212",
    city: "Dhaka",
  },
};
// Your code here:
const {address} = person;
const {street, zip} = address;
console.log(`street = ${street}, zip = ${zip}`)
// Expected: street = "123 Main St", zip = "1212"


// Problem 4: Array Destructuring Swap
// Swap the values of x and y using array destructuring — one line only.
let x = 100;
let y = 200;
// Your code here:
[x, y] = [y, x]
console.log("Problem 4:", { x, y }); // Expected: { x: 200, y: 100 }


// Problem 5: Skip Elements
// Given the scores array, extract only 1st and 3rd scores using destructuring.
// Ignore the 2nd score.
const scores = [88, 72, 95, 60];
// Your code here:
const [first,,third,] = scores;
console.log(`first = ${first}, third = ${third}`)
// Expected: first = 88, third = 95


// Problem 6: Function Parameter Destructuring
// Rewrite this function to use destructuring in the parameter.
// Original: function display(user) { console.log(user.name, user.role); }
function display({name, role}) {
  console.log(name+' '+role)
}
display({ name: "Sabbir", role: "developer", age: 25 });
// Expected output: "Sabbir developer"
